import { _decorator, Component, EventKeyboard, Input, input, KeyCode, log, Node, Prefab, v3, Vec3, sp, error, warn, Mask, UITransform} from 'cc';
import { SymbolSpine } from './SymbolSpine';
import { EffectSpine } from './EffectSpine';
import Game_Define from '../Game_Define';
import GameView from '../GameView';
import BaseNodePool from '../Common/BaseNodePool';
import { Define, tools } from 'db://astarte-framework/utilis';
import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
// import protocol from "./Test/ar2pq9Proto.js";
import { Common } from '../Common/Common';
import { eventManager } from 'db://astarte-framework/Managers';
import { REEL_UI_MANAGER_EVENT } from '../Reel/ReelManager';
import { PrefabPoolManager } from '../Common/PrefabPoolManager';
import { BaseSpine } from '../Spine/BaseSpine';
import { SymbolChange } from '../SymbolChange';
import { AudioManager } from '../Audio/AudioManager';
import { DEBUG } from 'cc/env';
import { NearWinEffectComponent } from "db://astarte-framework/Component/NearWinEffectComponent";
import { MultiplyFlyUI } from './MultiplyFlyUI';
import SpineKit from "db://astarte-framework/Component/Spine/SpineKit";
import { WantedPosterItem } from '../WantedPoster/WantedPosterItem';
const { ccclass, property } = _decorator;

/**@ch Scatter進入動畫 Prefab Key*/
export const SCATTER_ANIMATION_PREFAB_KEY0 = "ScatterAnimationPrefab0";
export const SCATTER_ANIMATION_PREFAB_KEY1 = "ScatterAnimationPrefab1";
export const SCATTER_ANIMATION_PREFAB_KEY2 = "ScatterAnimationPrefab2";

/**@ch Scatter預中獎 Node Key*/
export const SCATTER_PRE_WIN_NODE_KEY = "ScatterPreWinNode";

/**@ch Scatter進入動畫 Spine Key*/
export const SCATTER_ENTER_ANIMATION_SPINE_KEY = "NearWin";

/**@ch Scatter停輪動畫 Spine Key*/
export const SCATTER_STOP_ANIMATION_SPINE_KEY = "Stop";

/**@ch Scatter閒置動畫 Spine Key*/
export const SCATTER_IDLE_ANIMATION_SPINE_KEY = "Idle";

/**@ch Scatter中獎動畫 Spine Key*/
export const SCATTER_WIN_ANIMATION_SPINE_KEY_LV0 = "Win";
export const SCATTER_WIN_ANIMATION_SPINE_KEY_LV1 = "Collect";
export const SCATTER_WIN_ANIMATION_SPINE_KEY_LV2 = "Collect";
// /**@ch Symbol變化效果 Prefab Key*/
// export const SYMBOL_CHANGE_EFFECT_PREFAB_KEY = "SymbolChangeEffectPrefab";

//---------------------------------------------------
/**@ch Symbol消除效果 Prefab Key*/
export const SYMBOL_REMOVE_EFFECT_PREFAB_KEY = "SymbolRemoveEffectPrefab";

/**@ch 標靶爆炸 Prefab Key*/
export const TARGET_EXPLODE_PREFAB_KEY = "TargetExplodePrefab";

/**@ch 標靶 Symbol Spine Prefab Key（普通）*/
export const TARGET_SYMBOL_PREFAB_KEY = "TargetSymbolPrefab";

/**@ch 標靶 Symbol Spine Prefab Key（金）*/
export const TARGET_SYMBOL_GOLD_PREFAB_KEY = "TargetSymbolGoldPrefab";

/**@ch 乘倍飛行 Prefab Key*/
export const MULTI_FLY_PREFAB_KEY = "MultiFlyPrefab";

/**@ch 場上 Wanted Spine 的 PrefabPoolManager key（使用與常駐相同的 WantedPosterItem prefab） */
export const WANTED_SYMBOL_SPINE_PREFAB_KEY = "WantedSymbolSpine";

/**@ch Scatter中獎動畫後，等待音效播放完畢*/
const WAIT_AFTER_SCATTER_BINGO_SFX_SEC = 3;

@ccclass('EffectPlate')
export default class EffectPlate extends Component {
    //#region Property
    @property( {
        type: Prefab,
        tooltip: "symbol動態Prefabs"
    } )
    private m_symbolEffectPrefabs: Prefab[] = [];

    @property( {
        type: Prefab,
        tooltip: "symbol 共用動態Prefabs"
    } )
    private m_symbolAddEffectPrefabs: Prefab[] = [];

    @property( {
        type: Node,
        tooltip: "symbol相關表演的節點們"
    } )
    private m_effectNodes: Node[] = [];

    /**Scatter進入動畫 Prefab*/
    @property( {
        type: Prefab,
        tooltip: "Scatter動畫 level0 Prefab"
    } )
    private m_scatterEnterAnimationPrefab: Prefab = null;

    @property( {
        type: Prefab,
        tooltip: "Scatter動畫 level1 Prefab"
    } )
    private m_scatterEnterAnimationPrefab1: Prefab = null;

    @property( {
        type: Prefab,
        tooltip: "Scatter動畫 level2 Prefab"
    } )
    private m_scatterEnterAnimationPrefab2: Prefab = null;

    /**Scatter預中獎動畫 Prefab*/
    @property( {
        type: Prefab,
        tooltip: "Scatter預中獎動畫 Prefab"
    } )
    private m_scatterPreWinAnimationPrefab: Prefab = null;

    /**Symbol掉落效果 Prefab*/
    @property( {
        type: Prefab,
        tooltip: "Symbol掉落效果 Prefab"
    } )
    private m_symbolFallEffectPrefab: Prefab = null;

    // /**Symbol變化效果 Prefab*/
    // @property( {
    //     type: Prefab,
    //     tooltip: "Symbol變化效果 Prefab"
    // } )
    // private m_symbolChangeEffectPrefab: Prefab = null;

//------------------------------------------------
    @property( {
        type: Prefab,
        tooltip: "消除特效"
    } )
    private m_symbolRemovePrefab: Prefab = null;
    @property( {
        type: Prefab,
        tooltip: "乘倍飛行"
    } )
    private m_multiFlyPrefab: Prefab = null;
    @property( {
        type: sp.Skeleton,
        tooltip: "乘倍爆炸 spine"
    } )
    private m_multBombSpine: sp.Skeleton = null;
    @property( {
        type: sp.Skeleton,
        tooltip: "大獎預告 spine"
    } )
    private m_aimSpine: sp.Skeleton = null;
    @property( {
        type: NearWinEffectComponent,
        tooltip: "NearWin 輪帶特效"
    } )
    private m_nearWinEffects: NearWinEffectComponent[] = [];

    @property( {
        type: Prefab,
        tooltip: "標靶爆炸 prefab (Target_Explode)"
    } )
    private m_targetExplodePrefab: Prefab = null;

    @property( {
        type: Prefab,
        tooltip: "標靶 Symbol Spine prefab (Symbol_10)"
    } )
    private m_targetSymbolPrefab: Prefab = null;

    @property( {
        type: Prefab,
        tooltip: "金標靶 Symbol Spine prefab (Symbol_10_G)"
    } )
    private m_targetSymbolGoldPrefab: Prefab = null;

    @property( {
        type: Prefab,
        tooltip: "場上 Wanted Spine 的 prefab（含 sp.Skeleton + Wanted.skel，與常駐相同 prefab）"
    } )
    private m_wantedSymbolSpinePrefab: Prefab = null;
    //#endregion Property

    //#region Variable
    /**@ch 單線表演，為二維陣列 => col, row */
    private m_curAwardLines: Array<number>[] = [];
    public get CurAwardLines()
    {
        return this.m_curAwardLines;
    }

    /**@ch 放當前表演的Spine們，為三維陣列 => col, row, layers(表演有上下層) */
    private m_symbolSpines: Array<Array<Array<SymbolSpine>>> = new Array<Array<Array<SymbolSpine>>>();

    /**@ch 放當前共用表演的Spine們(目前只有中獎框)，為二維陣列 => col, row */
    private m_symbolAddEffectSpineNodes: Array<Array<Node>> = new Array<Array<Node>>();

    /**@ch 放當前Scatter進入動畫的節點們，Map<position, BaseSpine> */
    private m_scatterAnimationSpines: Map<number, BaseSpine> = new Map();

    /**@ch 放當前Scatter預中獎動畫的節點們，Map<col, Node> */
    private m_scatterPreWinNodes: Map<number, Node> = new Map();

    /**@ch 放當前Symbol掉落效果的節點們，Map<position, Node> */
    private m_symbolFallEffectNodes: Map<number, Node> = new Map();

    /**@ch 放當前Symbol變化效果的節點們，Map<position, Node> */
    private m_symbolChangeEffectNodes: Map<number, Node> = new Map();

    /**@ch 場上 Wanted Spine spawn 時的縮放倍率（預設 0.6）*/
    private m_wantedSymbolSpineScale: number = 0.85;

    /**@ch 遊戲視圖*/
    private m_gameView: GameView = null;
    /** 追蹤標靶停輪 Spine 節點（key=position, value={node, prefabKey}）*/
    private m_targetStopNodes: Map<number, {node: Node, prefabKey: string}> = new Map();
    /**@ch Scatter 停輪累計數（每次 Spin 重置）*/
    private m_scatterStopCount: number = 0;
    //#endregion Variable

    onLoad()
    {
        for ( let i = 0; i < Game_Define.COL; i++ )
            {
                let t = [];
                for ( let j = 0; j < Game_Define.ROW; j++ )
                    {
                        let ss = new Array<SymbolSpine>();
                ss.length = Game_Define.EFFECT_LAYER_NUMS;
                t.push( ss );
            }

            this.m_symbolSpines.push( t );
            this.m_symbolAddEffectSpineNodes.push( new Array<Node>() );
        }

    }

    /**
     * @ch 初始化EffectPlate
     * @param gameView 遊戲視圖
     */
    Init(gameView: GameView) {
        this.m_gameView = gameView;
        this.InitPool();
    }

    /**
     * @ch 初始化Pool
     */
    private InitPool() {
        BaseNodePool.getInstance().Init();

        if (this.m_symbolEffectPrefabs?.length > 0) {
            BaseNodePool.getInstance().SetPrefabs(this.m_symbolEffectPrefabs, Game_Define.EFFECT_TYPE.SYMBOL);
        }

        if (this.m_symbolAddEffectPrefabs?.length > 0) {
            BaseNodePool.getInstance().SetPrefabs(this.m_symbolAddEffectPrefabs, Game_Define.EFFECT_TYPE.ADD_EFFECT);
        }

        if (this.m_scatterEnterAnimationPrefab) {
            PrefabPoolManager.GetInstance().RegisterPrefab( SCATTER_ANIMATION_PREFAB_KEY0, this.m_scatterEnterAnimationPrefab );
        }

        if (this.m_scatterEnterAnimationPrefab1) {
            PrefabPoolManager.GetInstance().RegisterPrefab( SCATTER_ANIMATION_PREFAB_KEY1, this.m_scatterEnterAnimationPrefab1 );
        }

        if (this.m_scatterEnterAnimationPrefab2) {
            PrefabPoolManager.GetInstance().RegisterPrefab( SCATTER_ANIMATION_PREFAB_KEY2, this.m_scatterEnterAnimationPrefab2 );
        }

        if (this.m_scatterPreWinAnimationPrefab) {
            PrefabPoolManager.GetInstance().RegisterPrefab(SCATTER_PRE_WIN_NODE_KEY, this.m_scatterPreWinAnimationPrefab);
        }

        //---------------------------------------------------

        if(this.m_symbolRemovePrefab)
        {
            PrefabPoolManager.GetInstance().RegisterPrefab(SYMBOL_REMOVE_EFFECT_PREFAB_KEY, this.m_symbolRemovePrefab);
        }
        if(this.m_multiFlyPrefab)
        {
            PrefabPoolManager.GetInstance().RegisterPrefab(MULTI_FLY_PREFAB_KEY, this.m_multiFlyPrefab);
        }

        if(this.m_targetExplodePrefab)
        {
            PrefabPoolManager.GetInstance().RegisterPrefab(TARGET_EXPLODE_PREFAB_KEY, this.m_targetExplodePrefab);
        }

        if(this.m_targetSymbolPrefab)
        {
            PrefabPoolManager.GetInstance().RegisterPrefab(TARGET_SYMBOL_PREFAB_KEY, this.m_targetSymbolPrefab);
        }

        if(this.m_targetSymbolGoldPrefab)
        {
            PrefabPoolManager.GetInstance().RegisterPrefab(TARGET_SYMBOL_GOLD_PREFAB_KEY, this.m_targetSymbolGoldPrefab);
        }

        if(this.m_wantedSymbolSpinePrefab)
        {
            PrefabPoolManager.GetInstance().RegisterPrefab(WANTED_SYMBOL_SPINE_PREFAB_KEY, this.m_wantedSymbolSpinePrefab);
        }

    }

    /**
     * @ch 取得目標符號Node之世界座標
     * @param col 列
     * @param row 行
     * @returns 世界座標
     */
    private GetSymbolNodeWorldPos(col: number, row: number): Vec3 {
        if (this.m_gameView.SlotReels) {
            return this.m_gameView.SlotReels.GetSymbolInitWorldPositionFromColRow(col, row);
        }
        return v3(0, 0, 0);
    }

    /**
     * @ch 取得目標符號Node之世界座標
     * @param position 位置
     * @returns 世界座標
     */
    private GetSymbolNodeWorldPosFromPosition(position: number): Vec3 {
        if (this.m_gameView.SlotReels) {
            return this.m_gameView.SlotReels.GetSymbolInitWorldPositionFromPosition(position);
        }
        return v3(0, 0, 0);
    }

    /**
     * @ch 清除符號表演
     * @param col 列
     * @param row 行
     * @param layer 層
     */
    private CleanSymbolAnim(col: number, row: number, layer: number) {
        const symbolSpine = this.m_symbolSpines[col][row][layer];
        if (symbolSpine) {
            BaseNodePool.getInstance().ReturnNode(
                Game_Define.EFFECT_TYPE.SYMBOL,
                symbolSpine.GetSymbolId(),
                symbolSpine.node
            );
            this.m_symbolSpines[col][row][layer] = null;
        }

        const addEffectNode = this.m_symbolAddEffectSpineNodes[col][row];
        if (addEffectNode) {
            BaseNodePool.getInstance().ReturnNode(
                Game_Define.EFFECT_TYPE.ADD_EFFECT,
                Game_Define.ADD_EFFECT_TYPE.WIN_FRAME_NORMAL,
                addEffectNode
            );
            this.m_symbolAddEffectSpineNodes[col][row] = null;
        }
    }

    /**
     * @ch 根據一維位置索引清除符號表演
     * @param postion 一維位置索引
     * @param layer 層
     */
    private CleanSymbolAnimByPostion(postion: number, layer: number) {
        const { col, row } = Common.GetColRowFromPosition(postion);
        this.CleanSymbolAnim(col, row, layer);
    }

    /**
     * @ch 設置中獎框表演節點的顯示狀態
     * @param col 列
     * @param row 行
     * @param isShow 是否顯示
     */
    SetAddEffectSpineNodeShow(col: number, row: number, isShow: boolean) {
        if (this.m_symbolAddEffectSpineNodes[col][row]) {
            this.m_symbolAddEffectSpineNodes[col][row].active = isShow;
        }
    }

    /**
     * @ch 隱藏所有中獎框表演
     */
    private HideAddEffectSpineNodes() {
        for (let col = 0; col < Game_Define.COL; ++col) {
            for (let row = 0; row < Game_Define.ROW; ++row) {
                this.SetAddEffectSpineNodeShow(col, row, false);
            }
        }
    }

    /**
     * @ch 顯示所有中獎框表演
     */
    private ShowAddEffectSpineNodes() {
        for (let col = 0; col < Game_Define.COL; ++col) {
            for (let row = 0; row < Game_Define.ROW; ++row) {
                this.SetAddEffectSpineNodeShow(col, row, true);
            }
        }
    }

    /**
     * @ch 歸還所有符號表演
     */
    /**
     * @ch 清掉所有 SYMBOL 層的贏分特效節點，恢復被蓋住的原始 symbol
     */
    private CleanAllSymbolWinEffect() {
        for (let col = 0; col < Game_Define.COL; ++col) {
            for (let row = 0; row < Game_Define.ROW; ++row) {
                if (this.m_symbolSpines[col][row][Game_Define.LAYERS.SYMBOL]) {
                    this.CleanSymbolAnim(col, row, Game_Define.LAYERS.SYMBOL);
                }
            }
        }
    }

    ReturnAll()
    {
        for (let col = 0; col < Game_Define.COL; ++col) {
            for (let row = 0; row < Game_Define.ROW; ++row) {
                for (let layer = 0; layer < Game_Define.EFFECT_LAYER_NUMS; ++layer) {
                    this.CleanSymbolAnim(col, row, layer);
                }
            }
        }

        this.ReturnAllScatterEnterAnimationNodes();
        this.ReturnAllScatterPreWinNodes();

    }

    /**
     * @ch 設定Reel黑幕顯示
     * @param isShow 是否顯示
     */
    public SetReelBlackMaskShow(isShow: boolean) {
        eventManager.Dispatch(isShow ? REEL_UI_MANAGER_EVENT.SHOW_BLACK_MASK : REEL_UI_MANAGER_EVENT.HIDE_BLACK_MASK);
    }

    /**
     * @ch NearWin 時重建盤面 Scatter spine 並播 NearWin 動畫
     */
    public RebuildScatterSpines() {
        // FG 中不重建（scatter 做 collect 不需要 NearWin 動畫）
        if (this.m_gameView.IsFreeGame) return;

        const roundQueue = this.m_gameView.SpinAck?.RoundQueue;
        if (!roundQueue) return;
        const plateQueue = roundQueue[this.m_gameView.CurRoundIndex]?.PlateQueue;
        if (!plateQueue) return;
        const plateSymbol = plateQueue[this.m_gameView.CurPlateIndex]?.PlateSymbol;
        if (!plateSymbol) return;

        for (let col = 0; col < plateSymbol.length; col++) {
            const colData = plateSymbol[col]?.Col;
            if (!colData) continue;
            for (let row = 0; row < colData.length; row++) {
                const sym = colData[row];
                if (sym !== Game_Define.Symbol.Scatter && 
                    sym !== Game_Define.Symbol.SilverScatter && 
                    sym !== Game_Define.Symbol.GoldScatter) continue;

                const position = col * Game_Define.ROW + row;
                if (this.m_scatterAnimationSpines.has(position)) continue;

                this.PlayScatterEnterAnimation(col, row, true);
            }
        }
    }

    /**
     * @ch 設定Symbol顯示
     * @param col 列
     * @param row 行
     * @param isShow 是否顯示
     */
    private SetSymbolShow(col: number, row: number, isShow: boolean) {
        this.m_gameView.SlotReels.SetSymbolShow(col, row, isShow);
    }

    /**
     * @ch 從NodePool中取得一個表演節點
     * @param col 列
     * @param row 行
     * @param layer 層
     * @param symbol 符號
     * @param scaleSize 縮放大小
     * @param isCheckShowAddEffect 是否檢查顯示中獎框
     * @returns 表演節點
     */
    private CreateEffectNode_NodePool(
        col: number,
        row: number,
        layer: number,
        symbol: number,
        isCheckShowAddEffect: boolean = true,
        scaleSize = v3(1, 1, 1)
    ): Node {
        // 目標擺放位置
        let target = this.m_symbolSpines[col][row][layer];
        if (target) // 檢查是否已有東西
        {
            target.node.active = true;
            return target.node;
        }

        const worldPos = this.GetSymbolNodeWorldPos(col, row);

        // 建立Symbol的Spine
        let symbolNode = BaseNodePool.getInstance().GetNode(Game_Define.EFFECT_TYPE.SYMBOL, symbol);
        let symbolSpine = symbolNode.getComponent(SymbolSpine);
        this.m_effectNodes[layer].addChild(symbolSpine.node);
        symbolSpine.node.name = (col * 10 + row).toString();
        symbolSpine.node.setScale(scaleSize);
        symbolSpine.node.setWorldPosition(worldPos);
        symbolSpine.node.active = true;
