    /** Symbol 消除表演
     * @description 時間2s，Win 1s + Remove 1s
     * */
    async ExplodeEffect( awardDataVec: protocol.ar2pq9Proto.IAwardData[], comboIdx: number )
    {
        // 解除 NearWin 炸彈壓黑，避免迴圈多次
        if ( comboIdx == 0 )
        {
            eventManager.Dispatch(REEL_UI_MANAGER_EVENT.SET_ALL_SYMBOL_BLACK_MASK_SHOW, false, false);

        }
        let promises: Promise<void>[] = [];
        // 配合音效做加速
        let speed = this.m_gameView.IsHardStop ? 2 : 1;
        for ( let awardData of awardDataVec )
        {
            let symbol = awardData.Symbol ? awardData.Symbol : 0;
            let posVec = awardData.EliminatePos;
            let isTargetSymbol = symbol === Game_Define.Symbol.Target || symbol === Game_Define.Symbol.GoldTarget;
            for ( let pos of posVec )
            {
                let col = Math.floor( pos / Game_Define.ROW );
                let row = pos % Game_Define.ROW;

                // 標靶消除範圍：用盤面實際 symbol 播 Remove，標靶自己位置跳過
                if (isTargetSymbol) {
                    // 標靶自己的位置不播（已由 PlayTargetExplodeEffect 處理）
                    const curPlateSymbol = this.m_gameView.SpinAck
                        .RoundQueue[this.m_gameView.CurRoundIndex]
                        .PlateQueue[this.m_gameView.CurPlateIndex]?.PlateSymbol;
                    const actualSymbol = (curPlateSymbol && curPlateSymbol[col]?.Col?.[row]) ?? symbol;
                    if (actualSymbol === Game_Define.Symbol.Target || actualSymbol === Game_Define.Symbol.GoldTarget) {
                        continue;
                    }
                    // 範圍內其他 symbol：用實際 symbol 播 Remove
                    symbol = actualSymbol;
                }

                let symbolNode = this.CreateEffectNode_NodePool(col, row, Game_Define.LAYERS.SYMBOL, symbol);

                let removeEffectNode = PrefabPoolManager.GetInstance().GetNode(SYMBOL_REMOVE_EFFECT_PREFAB_KEY);
                if (!removeEffectNode) {
                    error("removeEffectNode");
                    return;
                }


                // 取得 Spine 組件
                let removeEffect = removeEffectNode.getComponent(EffectSpine);
                if (!removeEffect) {
                    error("removeEffect");
                    PrefabPoolManager.GetInstance().ReturnNode(
                        SYMBOL_REMOVE_EFFECT_PREFAB_KEY,
                        removeEffectNode
                    );
                    return;
                }

                // 設定父節點
                removeEffectNode.setParent(this.m_effectNodes[Game_Define.LAYERS.PRIATE]);
                removeEffectNode.setWorldPosition(this.GetSymbolNodeWorldPos(col, row));

                let symbolSpine = symbolNode.getComponent( SymbolSpine );
                promises.push( new Promise(
                    async ( resolve ) =>
                    {
                        symbolSpine.SetTimeScale( speed );
                        symbolSpine.SetAnimKey("Remove");
                        symbolSpine.PlayAnim().then( () =>
                        {
                            symbolSpine.SetTimeScale( 1 );
                            this.CleanSymbolAnim(col, row, Game_Define.LAYERS.SYMBOL);
                        } );

                        removeEffect.SetTimeScale( speed );
                        removeEffect.PlayAnim().then( () =>
                        {
                            removeEffect.SetTimeScale( 1 );
                            PrefabPoolManager.GetInstance().ReturnNode(SYMBOL_REMOVE_EFFECT_PREFAB_KEY, removeEffectNode);
                            resolve();
                        } );


                    }
                ) );
            }
        }
        // 消除音效（已移除，改由乘倍階段播）
        let comboLvl = comboIdx >= 5 ? 5 : comboIdx + 1;
        let suffix = this.m_gameView.IsHardStop ? "_F" : "";
        let soundKey = `Combo_0${comboLvl}${suffix}`;
        // AudioManager.Play(AudioManager.AudioClips[soundKey]);
        eventManager.Dispatch(REEL_UI_MANAGER_EVENT.SET_ALL_SYMBOL_BLACK_MASK_SHOW, true, false);
        await Promise.all( promises );

        eventManager.Dispatch(REEL_UI_MANAGER_EVENT.SET_ALL_SYMBOL_BLACK_MASK_SHOW, false, false);
    }

    /** 消除調整節點 Row
     * @description 傳入的位置應沒有動態節點，不必回收節點
    */
    TileMatching( col: number, row: number)
    {

        this.m_symbolSpines[ col ].splice( row, 1 );

        let newLayerSpines = new Array<SymbolSpine>();
        newLayerSpines.length = Game_Define.EFFECT_LAYER_NUMS;
        this.m_symbolSpines[ col ].push(newLayerSpines);
    }

    ReelStopEffect( col: number, row: number, symbol: number, mult: number )
    {
        if ( symbol == Game_Define.Symbol.GoldTarget || symbol == Game_Define.Symbol.Target )
        {
            // 標靶停輪音效 + 用 TargetSymbolPrefab 播 Stop→Idle
            const isGold = symbol == Game_Define.Symbol.GoldTarget;
            AudioManager.Play(isGold ? AudioManager.AudioClips.Target_Super : AudioManager.AudioClips.Target);
            const prefabKey = isGold ? TARGET_SYMBOL_GOLD_PREFAB_KEY : TARGET_SYMBOL_PREFAB_KEY;
            const position = Common.GetPositionFromColRow(col, row);
            // 同位置已有標靶時先歸還舊的（防止覆蓋遺失）
            const existing = this.m_targetStopNodes.get(position);
            if (existing?.node) {
                existing.node.active = false;
                PrefabPoolManager.GetInstance().ReturnNode(existing.prefabKey, existing.node);
            }
            const symbolNode = PrefabPoolManager.GetInstance().GetNode(prefabKey);
            if (symbolNode) {
                const spine = symbolNode.getComponent(BaseSpine);
                if (spine) {
                    symbolNode.setParent(this.m_effectNodes[Game_Define.LAYERS.SYMBOL]);
                    symbolNode.setWorldPosition(this.GetSymbolNodeWorldPos(col, row));
                    symbolNode.active = true;
                    const position = Common.GetPositionFromColRow(col, row);
                    this.m_targetStopNodes.set(position, {node: symbolNode, prefabKey: prefabKey});
                    log(`[TargetDiag] ReelStopEffect『播IN(Stop)』 col=${col} row=${row} symbol=${symbol}(${isGold ? 'Gold' : 'Normal'})`);
                    spine.PlayAnimation("Stop", spine.Spine, false).then(() => {
                        spine.PlayAnimation("Idle", spine.Spine, true);
                    });
                } else {
                    log(`[TargetDiag] ReelStopEffect『無IN』BaseSpine元件缺失 col=${col} row=${row} prefab=${prefabKey}`);
                    PrefabPoolManager.GetInstance().ReturnNode(prefabKey, symbolNode);
                }
            } else {
                log(`[TargetDiag] ReelStopEffect『無IN』pool取不到node col=${col} row=${row} prefab=${prefabKey}`);
            }
        }
        else if ( 
            symbol == Game_Define.Symbol.GoldScatter || 
            symbol == Game_Define.Symbol.SilverScatter || 
            symbol == Game_Define.Symbol.Scatter )
        {
            this.m_scatterStopCount++;
            log(`[Scatter Audio] ReelStopEffect col=${col} row=${row} symbol=${symbol} count=${this.m_scatterStopCount}`);
            this.PlayScatterStopSound(this.m_scatterStopCount);
        }
    }

    /**@ch 重置 Scatter 停輪計數（每次 Spin 開始時呼叫）*/
    ResetScatterStopCount(): void { this.m_scatterStopCount = 0; }

    /**@ch 根據累計數播 Scatter 停輪音效*/
    private PlayScatterStopSound(count: number): void {
        log(`[Scatter Audio] PlayScatterStopSound count=${count}`);
        if (this.m_gameView.IsFreeGame) {
            AudioManager.Play(AudioManager.AudioClips.FG_Scatter_stop);
            return;
        }
        if (count >= 5) {
            AudioManager.Play(AudioManager.AudioClips.Scatter5);
        } else if (count === 4) {
            AudioManager.Play(AudioManager.AudioClips.Scatter4);
        } else if (count === 3) {
            AudioManager.Play(AudioManager.AudioClips.Scatter3);
        } else if (count === 2) {
            AudioManager.Play(AudioManager.AudioClips.Scatter2);
        } else if (count >= 1) {
            AudioManager.Play(AudioManager.AudioClips.Scatter1);
        }
    }

    GetSymbolNode( col: number, row: number , layer: number): Node
    {
        if(this.m_symbolSpines[col][row][layer])
        {
            return this.m_symbolSpines[col][row][layer].node;
        }
        else
        {
            return null;
        }

    }



    /**
     * @ch 歸還消除表演節點
     * @param positions 位置
     * @param isRecoverSymbolShow 是否恢復Symbol顯示
     */
    ReturnEliminateEffectNodes(positions: number[], isRecoverSymbolShow: boolean) : void {
        if (positions.length === 0) {
            return;
        }

        for (const symbolPosition of positions) {
            const { col, row } = Common.GetColRowFromPosition(symbolPosition);
            if (isRecoverSymbolShow) {
                this.SetSymbolShow(col, row, true);
            }
            this.CleanSymbolAnim(col, row, Game_Define.LAYERS.PRIATE);
        }
    }
    //#endregion Eliminate



